import type { IdempotencyStore } from "../idempotency/idempotency-store.ts";
import type { Ledger } from "../ledger/ledger.ts";

export type RefundSucceeded = {
  id: string;
  type: "refund.succeeded";
  customerId: string;
  amount: number;
};

export class RefundHandler {
  private readonly ledger: Ledger;
  private readonly idempotency: IdempotencyStore;
  constructor(ledger: Ledger, idempotency: IdempotencyStore) {
    this.ledger = ledger;
    this.idempotency = idempotency;
  }

  async handle(event: RefundSucceeded): Promise<void> {
    if (await this.idempotency.has(event.id)) return;
    await this.ledger.credit({ customerId: event.customerId, amount: event.amount, eventId: event.id });
    // A timeout here allows the retry to credit the customer again.
    await this.idempotency.mark(event.id);
  }
}
import type { IdempotencyStore } from "../idempotency/idempotency-store.ts";
import type { Ledger, LedgerEntry } from "../ledger/ledger.ts";

/** Governing contract: the durable ledger owns uniqueness; the marker is a repairable cache. */
export interface TransactionBoundary {
  creditOnce(eventId: string, entry: LedgerEntry): Promise<"applied" | "duplicate">;
}

export class MemoryTransactionBoundary implements TransactionBoundary {
  private readonly ledger: Ledger;
  private readonly idempotency: IdempotencyStore;
  constructor(ledger: Ledger, idempotency: IdempotencyStore) {
    this.ledger = ledger;
    this.idempotency = idempotency;
  }
  async creditOnce(eventId: string, entry: LedgerEntry): Promise<"applied" | "duplicate"> {
    // The durable ledger is authoritative. A marker may be missing or stale and must
    // never suppress a legitimate ledger write.
    const result = await this.ledger.creditOnce(entry);
    if (!await this.idempotency.has(eventId)) await this.idempotency.mark(eventId);
    return result;
  }
}

/** Factory kept explicit so the handler depends on the governing transaction contract. */
export function transactionBoundaryFor(ledger: Ledger, idempotency: IdempotencyStore): TransactionBoundary {
  return new MemoryTransactionBoundary(ledger, idempotency);
}
export type LedgerEntry = { customerId: string; amount: number; eventId: string };

export interface Ledger {
  credit(entry: LedgerEntry): Promise<void>;
  /** Durable atomic insert keyed by eventId; production implementations use a unique constraint. */
  creditOnce(entry: LedgerEntry): Promise<"applied" | "duplicate">;
}

export class MemoryLedger implements Ledger {
  readonly entries: LedgerEntry[] = [];
  private readonly eventIds = new Set<string>();
  async credit(entry: LedgerEntry): Promise<void> {
    this.entries.push(entry);
  }
  async creditOnce(entry: LedgerEntry): Promise<"applied" | "duplicate"> {
    if (this.eventIds.has(entry.eventId)) return "duplicate";
    this.eventIds.add(entry.eventId);
    this.entries.push(entry);
    return "applied";
  }
}
export interface IdempotencyStore {
  has(eventId: string): Promise<boolean>;
  mark(eventId: string): Promise<void>;
}

export class MemoryIdempotencyStore implements IdempotencyStore {
  readonly processed = new Set<string>();
  async has(eventId: string): Promise<boolean> { return this.processed.has(eventId); }
  async mark(eventId: string): Promise<void> { this.processed.add(eventId); }
}
